import{_ as e,o as i,c as l,a2 as s}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"使用行为分析、热图、搜索、错误与支持数据验证问题","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/validation/08-analytics-heatmaps-search-errors-support.md","filePath":"03-interaction-design/notes/validation/08-analytics-heatmaps-search-errors-support.md","lastUpdated":1784248569000}'),n={name:"03-interaction-design/notes/validation/08-analytics-heatmaps-search-errors-support.md"};function t(r,a,p,o,d,h){return i(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="使用行为分析、热图、搜索、错误与支持数据验证问题" tabindex="-1">使用行为分析、热图、搜索、错误与支持数据验证问题 <a class="header-anchor" href="#使用行为分析、热图、搜索、错误与支持数据验证问题" aria-label="Permalink to &quot;使用行为分析、热图、搜索、错误与支持数据验证问题&quot;">​</a></h1><p>行为分析、热图、站内搜索、错误日志和支持数据从不同角度记录产品使用与故障。它们能定位“哪里发生了什么”，通常不能单独解释用户为什么这样做。有效验证需要先定义任务和事件语义，再用多源数据、具体复现和定性证据解释机制。</p><h2 id="数据源与边界" tabindex="-1">数据源与边界 <a class="header-anchor" href="#数据源与边界" aria-label="Permalink to &quot;数据源与边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>数据源</th><th>能回答</th><th>不能单独回答</th></tr></thead><tbody><tr><td>行为分析</td><td>入口、步骤、完成、放弃、设备和时间分布</td><td>用户意图、理解和因果</td></tr><tr><td>点击/滚动热图</td><td>聚合位置上的点击或可见范围</td><td>DOM 语义、任务正确性、单个用户路径</td></tr><tr><td>会话回放</td><td>某些操作顺序与界面变化</td><td>用户思考、全部辅助技术行为；有隐私风险</td></tr><tr><td>站内搜索</td><td>查询语言、无结果、改写和结果点击</td><td>查询者最终是否正确完成现实目标</td></tr><tr><td>客户端/服务端错误</td><td>失败类型、频率、环境和调用链</td><td>用户是否看见或恢复</td></tr><tr><td>支持工单</td><td>用户描述、影响、绕过和长期问题</td><td>总体发生率；提交者有自选择偏差</td></tr></tbody></table><p>GOV.UK 明确建议不要只依赖数字分析，应结合支持、反馈、后台和其他数据。任何数据源都需要明确总体、采样、缺失和隐私边界。</p><h2 id="从问题到数据" tabindex="-1">从问题到数据 <a class="header-anchor" href="#从问题到数据" aria-label="Permalink to &quot;从问题到数据&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;任务问题与完成定义&quot;] --&gt; E[&quot;事件、属性和错误语义&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; C[&quot;采集与质量验证&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; A[&quot;分群、漏斗和趋势&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; H[&quot;形成原因假设&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; R[&quot;回放、支持、日志或任务复现&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; V[&quot;改动与前后验证&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>先定义完成结果，再设计事件。仅有页面浏览和按钮点击无法判断对象是否真正创建、支付或同步成功。</p><h2 id="事件模型" tabindex="-1">事件模型 <a class="header-anchor" href="#事件模型" aria-label="Permalink to &quot;事件模型&quot;">​</a></h2><h3 id="事件名称" tabindex="-1">事件名称 <a class="header-anchor" href="#事件名称" aria-label="Permalink to &quot;事件名称&quot;">​</a></h3><p>使用稳定的业务动作或状态：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import_started</span></span>
<span class="line"><span>import_upload_completed</span></span>
<span class="line"><span>import_processing_completed</span></span>
<span class="line"><span>import_partially_completed</span></span>
<span class="line"><span>import_failed</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>不要把 DOM 选择器或按钮颜色作为长期事件名。UI 改版后，业务语义仍应可比较。</p><h3 id="事件属性" tabindex="-1">事件属性 <a class="header-anchor" href="#事件属性" aria-label="Permalink to &quot;事件属性&quot;">​</a></h3><ul><li>任务或对象类型，不上传敏感内容；</li><li>入口、角色、平台、版本和实验组；</li><li>结果状态、错误类别和恢复操作；</li><li>数量、耗时阶段和网络条件；</li><li>关联 ID 使用安全、受控、可追踪但不公开的标识。</li></ul><p>不能把邮箱、搜索全文、密码、令牌、文件内容等直接发送到分析系统。根据法律、隐私政策、同意和最小化原则设计采集。</p><h3 id="事件时机" tabindex="-1">事件时机 <a class="header-anchor" href="#事件时机" aria-label="Permalink to &quot;事件时机&quot;">​</a></h3><p>“点击提交”是意图，不是成功。成功事件应在权威结果确认后触发；异步任务分开记录请求已接收、处理中和最终结果。</p><h3 id="去重" tabindex="-1">去重 <a class="header-anchor" href="#去重" aria-label="Permalink to &quot;去重&quot;">​</a></h3><p>页面刷新、网络重试和多端上报可能重复事件。使用事件 ID、任务 ID和服务端权威记录去重，说明按用户、会话、任务还是事件聚合。</p><h2 id="漏斗与完成率" tabindex="-1">漏斗与完成率 <a class="header-anchor" href="#漏斗与完成率" aria-label="Permalink to &quot;漏斗与完成率&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>完成率 = 满足预先定义完成条件的任务数 / 合格任务尝试数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>必须说明：</p><ul><li>分子何时产生；</li><li>分母如何识别新尝试；</li><li>时间窗口；</li><li>重试、返回和跨设备怎样归属；</li><li>不符合资格和机器人如何处理；</li><li>部分成功算成功、失败还是单独类别。</li></ul><p>步骤之间下降只表示记录中的用户未进入下一事件。原因可能是任务完成于别处、事件漏报、主动退出、不符合资格或真实阻碍。</p><h2 id="热图和会话回放" tabindex="-1">热图和会话回放 <a class="header-anchor" href="#热图和会话回放" aria-label="Permalink to &quot;热图和会话回放&quot;">​</a></h2><h3 id="热图验证" tabindex="-1">热图验证 <a class="header-anchor" href="#热图验证" aria-label="Permalink to &quot;热图验证&quot;">​</a></h3><ul><li>确认位置映射到正确版本、视口和 DOM；</li><li>按设备和布局分群，避免混合不同坐标；</li><li>点击密集不等于重要或成功，可能是错误重复点击；</li><li>无点击不等于不可用，键盘、语音和屏幕阅读器路径可能未记录；</li><li>滚动深度不等于阅读或理解。</li></ul><h3 id="回放验证" tabindex="-1">回放验证 <a class="header-anchor" href="#回放验证" aria-label="Permalink to &quot;回放验证&quot;">​</a></h3><p>回放用于复现某类事件前后的界面状态，而不是窥视个人。需要输入遮罩、敏感区域排除、访问控制、保留期限和审计。采集工具可能不还原 Canvas、Shadow DOM、辅助技术或网络状态，报告需说明限制。</p><h2 id="站内搜索数据" tabindex="-1">站内搜索数据 <a class="header-anchor" href="#站内搜索数据" aria-label="Permalink to &quot;站内搜索数据&quot;">​</a></h2><p>检查：</p><ul><li>查询量、无结果率与改写；</li><li>查询后点击与任务完成；</li><li>同义词、拼写、内部术语和敏感查询；</li><li>搜索结果是否显示足够上下文；</li><li>无结果后是清除筛选、换词、求助还是离开。</li></ul><p>搜索词可以揭示用户语言和信息架构缺口，但可能包含个人或敏感数据，需最小化、脱敏和限制访问。</p><h2 id="错误与支持数据" tabindex="-1">错误与支持数据 <a class="header-anchor" href="#错误与支持数据" aria-label="Permalink to &quot;错误与支持数据&quot;">​</a></h2><h3 id="错误分类" tabindex="-1">错误分类 <a class="header-anchor" href="#错误分类" aria-label="Permalink to &quot;错误分类&quot;">​</a></h3><p>将错误分为输入、权限、业务规则、冲突、网络、服务、第三方和未知结果。HTTP 状态码是实现信号，不能直接当用户问题分类。</p><p>记录：错误码、版本、阶段、对象类型、请求 ID、是否重试、最终结果和用户可见反馈。堆栈与日志不得进入公开学习笔记。</p><h3 id="支持工单" tabindex="-1">支持工单 <a class="header-anchor" href="#支持工单" aria-label="Permalink to &quot;支持工单&quot;">​</a></h3><p>按任务、现象、环境、影响、绕过和结果编码。把“怎么用”“为什么不允许”“结果在哪里”“数据错了”等分开。工单数量受支持入口、用户群和运营变化影响，需结合任务尝试分母。</p><h2 id="完整案例-定位批量导入放弃" tabindex="-1">完整案例：定位批量导入放弃 <a class="header-anchor" href="#完整案例-定位批量导入放弃" aria-label="Permalink to &quot;完整案例：定位批量导入放弃&quot;">​</a></h2><h3 id="问题与数据" tabindex="-1">问题与数据 <a class="header-anchor" href="#问题与数据" aria-label="Permalink to &quot;问题与数据&quot;">​</a></h3><p>目标：判断成员导入为什么在“上传完成”后有大量任务没有最终结果。</p><p>14 天数据：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import_started：2,000 个唯一任务</span></span>
<span class="line"><span>upload_completed：1,760</span></span>
<span class="line"><span>processing_completed：1,100</span></span>
<span class="line"><span>partially_completed：180</span></span>
<span class="line"><span>failed：220</span></span>
<span class="line"><span>没有最终事件：260</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>数据质量检查发现 <code>processing_completed</code> 由前端结果页触发，用户离开后后台成功不会上报，因此“没有最终事件”不能直接解释为失败。</p><h3 id="修正事件模型" tabindex="-1">修正事件模型 <a class="header-anchor" href="#修正事件模型" aria-label="Permalink to &quot;修正事件模型&quot;">​</a></h3><ol><li>以服务端导入任务为分母，使用任务 ID 去重。</li><li>最终状态由服务端权威事件产生：complete、partial、failed。</li><li>前端另记 <code>result_viewed</code>，表示用户看过结果。</li><li>记录上传、排队、处理和通知的阶段耗时。</li></ol><p>修正后同一 2,000 任务：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>服务端完成：1,520</span></span>
<span class="line"><span>部分完成：220</span></span>
<span class="line"><span>失败：240</span></span>
<span class="line"><span>仍处理中超过内部阈值：20</span></span>
<span class="line"><span>结果被查看：1,080</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="多源分析" tabindex="-1">多源分析 <a class="header-anchor" href="#多源分析" aria-label="Permalink to &quot;多源分析&quot;">​</a></h3><ul><li>错误日志：失败中 140 个为 CSV 表头错误，80 个权限变化，20 个服务故障。</li><li>站内搜索：“导入记录”“上传后去哪看”查询在导入用户中明显出现。</li><li>支持工单：38 个询问上传后结果位置；多数从上传页离开。</li><li>回放抽样：结果入口只在成员页次级菜单，部分用户重复上传。</li></ul><p>这些证据支持“最终任务多已完成，但结果入口和状态通知不足”；它们仍不能说明所有未查看用户都找不到入口，有些可能无需查看。</p><h3 id="改动" tabindex="-1">改动 <a class="header-anchor" href="#改动" aria-label="Permalink to &quot;改动&quot;">​</a></h3><ol><li>上传完成后显示持久任务 ID 和“可以离开，导入记录中继续查看”。</li><li>成员页增加当前导入状态区域，而不是只放在菜单。</li><li>完成、部分成功和失败发送可配置通知，深链到任务。</li><li>重复文件上传时提示已有任务。</li><li>修复 CSV 表头在上传前可检查的部分，但服务端继续权威验证。</li></ol><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><ul><li>分析脚本重复计算客户端和服务端成功：使用任务 ID 与事件来源区分。</li><li>事件漏报：每日与任务表对账。</li><li>通知点击高但完成未变：检查用户只是查看，还是能修正失败项。</li><li>结果入口增加后支持下降：同时检查任务量、版本和支持渠道变化，避免错误归因。</li></ul><h3 id="验证输出" tabindex="-1">验证输出 <a class="header-anchor" href="#验证输出" aria-label="Permalink to &quot;验证输出&quot;">​</a></h3><p>发布后比较同一口径：最终状态完整率、结果查看、重复上传、失败修正和支持率。分阶段发布时保留对照组与版本属性；高风险问题不用仅靠指标决定，仍执行键盘、状态和任务复现。</p><h2 id="数据质量检查" tabindex="-1">数据质量检查 <a class="header-anchor" href="#数据质量检查" aria-label="Permalink to &quot;数据质量检查&quot;">​</a></h2><ul><li>事件文档与实现是否一致；</li><li>客户端、服务端时间与时区；</li><li>事件重复、延迟、丢失和顺序；</li><li>版本、实验组和平台属性；</li><li>用户/会话/任务 ID 作用域；</li><li>隐私同意导致的缺失；</li><li>机器人、内部账户和测试数据；</li><li>指标查询可重复且有版本控制。</li></ul><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>把点击当成功：用权威对象结果定义完成。</li><li>漏斗下降直接解释为困惑：补复现、支持或任务证据。</li><li>混合不同平台、版本和实验组。</li><li>热图只看颜色，不看视口、DOM 和键盘路径。</li><li>会话回放采集敏感输入或长期无限保留。</li><li>用错误数量不除以任务尝试或流量。</li><li>修改事件定义后仍与旧数据直接比较。</li><li>只看平均值，隐藏长尾、分群和失败类别。</li></ul><h2 id="可执行步骤" tabindex="-1">可执行步骤 <a class="header-anchor" href="#可执行步骤" aria-label="Permalink to &quot;可执行步骤&quot;">​</a></h2><ol><li>定义任务、合格尝试、成功、部分成功与失败。</li><li>设计业务语义事件、属性、时机和去重范围。</li><li>核对隐私、同意、最小化、保留和访问控制。</li><li>验证事件与权威数据对账，记录缺失和版本。</li><li>按平台、角色、版本和入口分析漏斗与错误。</li><li>使用搜索、支持、回放和复现解释假设。</li><li>设计改动、失败分支和可比较指标。</li><li>发布后按同一口径验证，并检查非预期影响。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为“搜索并打开文档”建立验证方案。</p><p>完成时应满足：</p><ul><li>定义搜索尝试、有效查询、结果点击和文档成功打开；</li><li>区分无结果、错误、权限过滤和用户主动离开；</li><li>事件不采集敏感查询全文或个人数据；</li><li>站内搜索、错误、支持和任务复现至少三源交叉；</li><li>按平台、版本和角色分群；</li><li>事件与搜索后端权威日志完成对账；</li><li>结论不把相关性写成原因，改动有前后同口径验证。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.gov.uk/service-manual/measuring-success/using-data-to-improve-your-service-an-introduction" target="_blank" rel="noreferrer">GOV.UK Service Manual：Using performance data to improve your service</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/measuring-the-success-of-your-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Measuring the success of your service</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/choosing-digital-analytics-tools" target="_blank" rel="noreferrer">GOV.UK Service Manual：Choosing digital analytics tools</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/helping-people-to-use-your-service/set-up-and-manage-user-support" target="_blank" rel="noreferrer">GOV.UK Service Manual：Set up and manage user support</a>（访问日期：2026-07-17）</li></ul>`,72)])])}const b=e(n,[["render",t]]);export{u as __pageData,b as default};
